/// <summary>
/// Controller class for Etg_Register_SalesReport.
/// Selects design 'Register_Saleso001' for legal entity O001
/// and 'Register_Sales' for all other legal entities.
/// </summary>
class Etg_RegisterSalesReportController extends SrsReportRunController
{
}

Method.Source:
/// <summary>
/// Main entry point for the report.
/// </summary>
public static void main(Args _args)
{
    Etg_RegisterSalesReportController controller = new Etg_RegisterSalesReportController();

    controller.parmReportName(ssrsReportStr(Etg_Register_SalesReport, Register_Sales));
    controller.parmArgs(_args);
    controller.startOperation();
}

/// <summary>
/// Switches the report design based on the current legal entity before execution.
/// </summary>
protected void prePromptModifyContract()
{
    super();

    if (curExt() == "O001")
    {
        this.parmReportName(ssrsReportStr(Etg_Register_SalesReport, Register_Saleso001));
    }
    else
    {
        this.parmReportName(ssrsReportStr(Etg_Register_SalesReport, Register_Sales));
    }
}
